/**
 * Server-only data access layer.
 *
 * This module must NEVER be imported by client-runnable code. It uses
 * `better-sqlite3` which depends on native Node bindings and must not end up
 * in the browser bundle. All imports from this file should originate from
 * `routeLoader$` or `server$()` callbacks so that the Qwik optimizer can
 * strip it out of the client graph.
 */
import Database from "better-sqlite3";
import { mkdirSync, existsSync } from "node:fs";
import { dirname, resolve } from "node:path";

export interface Post {
  id: number;
  title: string;
  body: string;
}

const PAGE_SIZE = 10;
const TOTAL_POSTS = 47;

const DB_PATH = resolve(process.cwd(), "data", "feed.db");

let _db: Database.Database | null = null;

function getDb(): Database.Database {
  if (_db) return _db;

  const dir = dirname(DB_PATH);
  if (!existsSync(dir)) {
    mkdirSync(dir, { recursive: true });
  }

  const db = new Database(DB_PATH);
  db.pragma("journal_mode = WAL");

  db.exec(`
    CREATE TABLE IF NOT EXISTS posts (
      id   INTEGER PRIMARY KEY,
      title TEXT NOT NULL,
      body  TEXT NOT NULL
    );
  `);

  const countRow = db
    .prepare("SELECT COUNT(*) as c FROM posts")
    .get() as { c: number };

  if (countRow.c < TOTAL_POSTS) {
    const insert = db.prepare(
      "INSERT INTO posts (id, title, body) VALUES (?, ?, ?)",
    );
    const insertMany = db.transaction(() => {
      // Wipe existing rows so re-seeding always converges to exactly 47 posts.
      db.exec("DELETE FROM posts");
      for (let n = 1; n <= TOTAL_POSTS; n++) {
        insert.run(n, `Post #${n}`, `This is the body of post number ${n}.`);
      }
    });
    insertMany();
  }

  _db = db;
  return _db;
}

export interface FeedPage {
  posts: Post[];
  hasMore: boolean;
}

/**
 * Return the first page of the feed (no cursor) – used by `routeLoader$`
 * during the initial server render.
 */
export function getInitialFeed(): FeedPage {
  const db = getDb();
  const rows = db
    .prepare(
      "SELECT id, title, body FROM posts ORDER BY id ASC LIMIT ?",
    )
    .all(PAGE_SIZE) as Post[];

  const total = (db.prepare("SELECT COUNT(*) as c FROM posts").get() as {
    c: number;
  }).c;

  return {
    posts: rows,
    hasMore: rows.length < total,
  };
}

/**
 * Return the page that comes after `cursor` (the id of the last loaded post).
 * Used by the `server$()` RPC that powers infinite scroll on the client.
 */
export function getFeedAfter(cursor: number): FeedPage {
  const db = getDb();
  const rows = db
    .prepare(
      "SELECT id, title, body FROM posts WHERE id > ? ORDER BY id ASC LIMIT ?",
    )
    .all(cursor, PAGE_SIZE) as Post[];

  const total = (db.prepare("SELECT COUNT(*) as c FROM posts").get() as {
    c: number;
  }).c;
  const lastLoaded =
    rows.length > 0 ? rows[rows.length - 1].id : cursor;
  const hasMore = lastLoaded < total;

  return {
    posts: rows,
    hasMore,
  };
}

import {
  component$,
  useStore,
  useSignal,
  useVisibleTask$,
  $,
  noSerialize,
  type NoSerialize,
} from "@builder.io/qwik";
import {
  routeLoader$,
  server$,
  type DocumentHead,
} from "@builder.io/qwik-city";
import type { Post } from "../server/db.server";

interface FeedPagePayload {
  posts: Post[];
  hasMore: boolean;
}

interface FeedStore {
  posts: Post[];
  cursor: number;
  hasMore: boolean;
  loading: boolean;
  finished: boolean;
}

/**
 * Initial page – executed on the server during SSR. The result is embedded
 * directly into the HTML so the first 10 posts are visible with no client
 * JavaScript having to run.
 */
export const useInitialFeed = routeLoader$(async (): Promise<FeedPagePayload> => {
  const { getInitialFeed } = await import("../server/db.server");
  return getInitialFeed();
});

/**
 * RPC for subsequent pages. Lives entirely on the server; `better-sqlite3`
 * is only required inside this callback so it can never leak into the
 * browser bundle.
 */
export const fetchNextFeedPage = server$(async function (
  cursor: number,
): Promise<FeedPagePayload> {
  const { getFeedAfter } = await import("../server/db.server");
  return getFeedAfter(cursor);
});

export default component$(() => {
  const initial = useInitialFeed();

  const store = useStore<FeedStore>({
    posts: initial.value.posts,
    cursor:
      initial.value.posts.length > 0
        ? initial.value.posts[initial.value.posts.length - 1].id
        : 0,
    hasMore: initial.value.hasMore,
    loading: false,
    finished: !initial.value.hasMore,
  });

  const observer = useSignal<NoSerialize<IntersectionObserver> | undefined>(
    undefined,
  );

  const loadNext = $(async () => {
    if (store.loading || store.finished || !store.hasMore) return;
    store.loading = true;
    try {
      const page = await fetchNextFeedPage(store.cursor);
      if (page.posts.length === 0) {
        store.hasMore = false;
        store.finished = true;
        return;
      }
      for (const post of page.posts) {
        store.posts.push(post);
      }
      store.cursor = page.posts[page.posts.length - 1].id;
      store.hasMore = page.hasMore;
      if (!page.hasMore) {
        store.finished = true;
      }
    } finally {
      store.loading = false;
    }
  });

  // eslint-disable-next-line qwik/no-use-visible-task
  useVisibleTask$(({ cleanup }) => {
    const sentinel = document.querySelector<HTMLElement>(
      '[data-testid="feed-sentinel"]',
    );
    if (!sentinel) return;

    const io = new IntersectionObserver(
      (entries) => {
        for (const entry of entries) {
          if (entry.isIntersecting) {
            // Fire and forget – `loadNext` handles its own loading flag.
            void loadNext();
          }
        }
      },
      { rootMargin: "100px" },
    );
    io.observe(sentinel);
    observer.value = noSerialize(io);

    cleanup(() => {
      io.disconnect();
    });
  });

  return (
    <main style={{ maxWidth: "640px", margin: "2rem auto", padding: "0 1rem" }}>
      <h1>Infinite Feed</h1>
      <ul style={{ listStyle: "none", padding: 0 }}>
        {store.posts.map((post) => (
          <li
            key={post.id}
            data-testid="feed-item"
            style={{
              border: "1px solid #ddd",
              borderRadius: "8px",
              padding: "1rem",
              marginBottom: "0.75rem",
            }}
          >
            <h2 style={{ margin: "0 0 0.5rem" }}>{post.title}</h2>
            <p style={{ margin: 0, color: "#444" }}>{post.body}</p>
          </li>
        ))}
      </ul>

      {store.hasMore && !store.finished && (
        <div
          data-testid="feed-sentinel"
          style={{ height: "1px", width: "100%" }}
        />
      )}

      {store.loading && (
        <div
          data-testid="feed-loading"
          style={{ padding: "1rem", textAlign: "center" }}
        >
          Loading more posts…
        </div>
      )}

      {store.finished && (
        <div
          data-testid="feed-end"
          style={{ padding: "1rem", textAlign: "center", fontWeight: 600 }}
        >
          End of feed – all {store.posts.length} posts loaded.
        </div>
      )}
    </main>
  );
});

export const head: DocumentHead = {
  title: "Infinite Feed",
  meta: [
    {
      name: "description",
      content: "Qwik City infinite-scroll feed backed by SQLite.",
    },
  ],
};

